+      const level = accountLevel ?? cfg.channels?.whatsapp?.reactionLevel ?? "minimal";
+      return {
+        level,
+        agentReactionsEnabled: level === "minimal" || level === "extensive",
+        agentReactionGuidance: level === "minimal" || level === "extensive" ? level : undefined,
+      };
+    },
+  };
+});
